  int_phase2_note: { vi: "Chờ cấu hình thiết bị / API key (Giai đoạn 2)", en: "Waiting for device / API key configuration (Phase 2)", zh: "等待设备/API密钥配置（第2阶段）", ja: "デバイス/APIキー設定待ち（フェーズ2）", ko: "장치/API 키 설정 대기 (2단계)", fr: "En attente de configuration appareil / clé API (Phase 2)" },
