  sc_fake_prev: { vi: "Nỗ Lực Làm Giả Bị Ngăn Chặn", en: "Fake Attempts Prevented", zh: "已阻止的伪造尝试", ja: "阻止した偽造試行", ko: "차단된 위조 시도", fr: "Tentatives de faux empêchées" },
