  sc_efficiency: { vi: "Hiệu Quả Chuỗi Cung Ứng", en: "Supply Chain Efficiency", zh: "供应链效率", ja: "サプライチェーン効率", ko: "공급망 효율", fr: "Efficacité de la chaîne" },
