  sc_live_traffic: { vi: "Lưu lượng thực tế trên các nút mạng toàn cầu", en: "Live traffic across global nodes", zh: "全球节点实时流量", ja: "グローバルノードのライブトラフィック", ko: "글로벌 노드의 실시간 트래픽", fr: "Trafic en direct sur les noeuds" },
